1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	interface Item {
5	  type: string;
6	}
7	
8	interface QuoteStep {
9	  items: Item[];
10	}
11	
12	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
13	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
14	// that is only spuriously above a whole number.
15	const roundUpInMHPCOsFavor = (amount: number): number =>
16	  Math.ceil(Number(amount.toFixed(6)));
17	
18	export const quote = (
19	  customer: unknown,
20	  step: QuoteStep,
21	  quoteIndex: number,
22	): number => {
23	  let basePremium = 0;
24	  for (const item of step.items) {
25	    if (item.type === "sword") basePremium += 100;
26	    if (item.type === "amulet") basePremium += 60;
27	  }
28	  const withFirstInsurance = basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
29	  const total = withFirstInsurance + PROCESSING_FEE;
30	  return roundUpInMHPCOsFavor(total);
31	};
32	
33	export const claim = (...args: unknown[]): unknown => {
34	  return undefined; // Intentionally not implemented
35	};
